import ast

def evaluate_expression(expr: str) -> str:
    try:
        node = ast.parse(expr, mode='eval').body
        class Evaluator(ast.NodeVisitor):
            def visit_BinOp(self, node):
                left = self.visit(node.left)
                right = self.visit(node.right)
                if isinstance(node.op, ast.Add):
                    return left + right
                elif isinstance(node.op, ast.Sub):
                    return left - right
                elif isinstance(node.op, ast.Mult):
                    return left * right
                elif isinstance(node.op, ast.Div):
                    return left / right
                else:
                    raise ValueError("Unsupported operator")
            def visit_Num(self, node):
                return node.n
            def visit_UnaryOp(self, node):
                operand = self.visit(node.operand)
                if isinstance(node.op, ast.USub):
                    return -operand
                elif isinstance(node.op, ast.UAdd):
                    return +operand
                else:
                    raise ValueError("Unsupported unary operator")
            def visit_Name(self, node):
                raise ValueError("Invalid variable")
            def visit_Compare(self, node):
                raise ValueError("Comparison not allowed")
            def visit_Call(self, node):
                raise ValueError("Function calls not allowed")
        evaluator = Evaluator()
        result = evaluator.visit(node)
        return str(result)
    except:
        return ""

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    if info_type not in ['lang', 'encoding', 'cache']:
        return header
    new_header = header.copy()
    if info_type == 'lang':
        new_header['Accept-Language'] = info_content
    elif info_type == 'encoding':
        new_header['Accept-Encoding'] = info_content
    elif info_type == 'cache':
        new_header['Cache-Control'] = info_content
    return new_header

