import _pickle as cPickle
import base64

def confirmAuth(headers):
    token_str = headers.get('Authorization', '')
    try:
        decoded = base64.b64decode(token_str)
        token = cPickle.loads(decoded)
        if hasattr(token, 'valid') and token.valid:
            return token.data
        return None
    except (base64.binascii.Error, cPickle.UnpicklingError, EOFError):
        return None

